// ── API helper ─────────────────────────────────────────────────────────────────
let DEMO_CLIENTS_STATE = [...DEMO_CLIENTS];
let DEMO_OFFERS_STATE = [...DEMO_OFFERS];

async function api(action, params = {}) {
  if (DEMO_MODE) {
    await new Promise(r => setTimeout(r, 250));
    switch(action) {
      case 'login': return params.pin === '1234' ? { ok: true } : { ok: false, error: 'Nieprawidłowy PIN (demo: 1234)' };
      case 'getConfig': return { ok: true, config: DEMO_CONFIG, products: DEMO_PRODUCTS };
      case 'getUsers': return { ok: true, users: DEMO_USERS };
      case 'getClients': return { ok: true, clients: DEMO_CLIENTS_STATE };
      case 'saveClient': {
        const newId = String(Date.now());
        if (params.id) {
          DEMO_CLIENTS_STATE = DEMO_CLIENTS_STATE.map(c => String(c.id) === String(params.id) ? { ...c, ...params } : c);
          return { ok: true, id: params.id };
        }
        DEMO_CLIENTS_STATE.push({ id: newId, nazwa_firmy: params.nazwa_firmy, adres: params.adres, nip: params.nip, telefon: params.telefon, email: params.email });
        return { ok: true, id: newId };
      }
      case 'deleteClient':
        DEMO_CLIENTS_STATE = DEMO_CLIENTS_STATE.filter(c => String(c.id) !== String(params.id));
        return { ok: true };
      case 'getCompanyInfo': return { ok: true, company: DEMO_COMPANY };
      case 'saveCompanyInfo': return { ok: true };
      case 'getRegister': return { ok: true, offers: DEMO_OFFERS_STATE };
      case 'getNextNumber': {
        const n = DEMO_OFFERS_STATE.length + 1;
        return { ok: true, nr: `O-MTS-2025-${String(n).padStart(3,'0')}` };
      }
      case 'saveOffer': return { ok: true };
      case 'updateOffer': return { ok: true, nr: params.offer?.nr_oferty };
      default: return { ok: true };
    }
  }
  const res = await fetch(BACKEND_URL, {
    method: 'POST',
    body: JSON.stringify({ action, ...params }),
  });
  return res.json();
}

