// USTAWIENIA
// ══════════════════════════════════════════════════════════════════════════════
function Settings({ users: initUsers, config, companyInfo, showToast, onSaved }) {
  const [users, setUsers] = useState(initUsers || []);
  const [newImie, setNewImie] = useState('');
  const [newNazwisko, setNewNazwisko] = useState('');
  const [editId, setEditId] = useState(null);
  const [saving, setSaving] = useState(false);

  const [company, setCompany] = useState(companyInfo || {});
  const [savingCompany, setSavingCompany] = useState(false);

  useEffect(() => { setUsers(initUsers || []); }, [initUsers]);
  useEffect(() => { if (companyInfo) setCompany(companyInfo); }, [companyInfo]);

  const handleAddUser = async () => {
    if (!newImie || !newNazwisko) { showToast('Podaj imię i nazwisko', 'error'); return; }
    setSaving(true);
    const res = await api('saveUser', { id: editId || null, imie: newImie, nazwisko: newNazwisko });
    if (res.ok) {
      showToast(editId ? 'Użytkownik zaktualizowany' : 'Użytkownik dodany');
      setNewImie(''); setNewNazwisko(''); setEditId(null);
      onSaved();
    } else showToast(res.error || 'Błąd', 'error');
    setSaving(false);
  };

  const handleDelete = async (id) => {
    if (!confirm('Na pewno usunąć tego użytkownika?')) return;
    const res = await api('deleteUser', { id });
    if (res.ok) { showToast('Użytkownik usunięty'); onSaved(); }
    else showToast(res.error || 'Błąd', 'error');
  };

  const handleEdit = (u) => {
    setEditId(u.id); setNewImie(u.imie); setNewNazwisko(u.nazwisko);
  };

  const handleSaveCompany = async () => {
    setSavingCompany(true);
    const res = await api('saveCompanyInfo', { company });
    if (res.ok) { showToast('Dane oferenta zapisane'); onSaved(); }
    else showToast(res.error || 'Błąd zapisu', 'error');
    setSavingCompany(false);
  };

  return (
    <div>
      <div className="grid2">
        {/* Użytkownicy */}
        <div className="card">
          <div className="card-title">Osoby przygotowujące oferty</div>
          <div style={{marginBottom:16}}>
            {users.map(u => (
              <div key={u.id} style={{display:'flex',alignItems:'center',gap:10,padding:'8px 0',borderBottom:`1px solid ${C.gray200}`}}>
                <div className="avatar">{u.imie?.[0]}{u.nazwisko?.[0]}</div>
                <div style={{flex:1}}>
                  <div style={{fontSize:13,fontWeight:600}}>{u.imie} {u.nazwisko}</div>
                </div>
                <button className="btn btn-ghost btn-sm" onClick={() => handleEdit(u)}>Edytuj</button>
                <button className="btn btn-danger btn-sm" onClick={() => handleDelete(u.id)}>✕</button>
              </div>
            ))}
            {users.length === 0 && <p style={{color:C.gray400,fontSize:13}}>Brak użytkowników.</p>}
          </div>

          <div style={{background:C.gray100,borderRadius:8,padding:14}}>
            <div style={{fontSize:12,fontWeight:600,color:C.teal,marginBottom:10}}>
              {editId ? 'Edytuj użytkownika' : 'Dodaj nowego'}
            </div>
            <div className="grid2" style={{marginBottom:10}}>
              <div className="field">
                <label>Imię</label>
                <input className="editable" placeholder="np. Anna" value={newImie} onChange={e => setNewImie(e.target.value)} />
              </div>
              <div className="field">
                <label>Nazwisko</label>
                <input className="editable" placeholder="np. Kowalska" value={newNazwisko} onChange={e => setNewNazwisko(e.target.value)} />
              </div>
            </div>
            <div style={{display:'flex',gap:8}}>
              <button className="btn btn-primary btn-sm" onClick={handleAddUser} disabled={saving}>
                {saving ? '…' : editId ? '✓ Zapisz zmiany' : '+ Dodaj'}
              </button>
              {editId && <button className="btn btn-ghost btn-sm" onClick={() => { setEditId(null); setNewImie(''); setNewNazwisko(''); }}>Anuluj</button>}
            </div>
          </div>
        </div>

        {/* Dane oferenta */}
        <div className="card">
          <div className="card-title">Dane oferenta (widoczne na ofercie PDF)</div>
          <div style={{display:'flex',alignItems:'center',gap:14,marginBottom:14}}>
            <img src={LOGO_BASE64} alt="Logo" style={{height:50,objectFit:'contain'}} />
            <span style={{fontSize:11,color:C.gray400}}>Logo wbudowane w aplikację — do zmiany przez programistę.</span>
          </div>
          <div className="field" style={{marginBottom:10}}>
            <label>Nazwa firmy</label>
            <input className="editable" value={company.nazwa_firmy || ''} onChange={e => setCompany(c => ({...c, nazwa_firmy: e.target.value}))} />
          </div>
          <div className="field" style={{marginBottom:10}}>
            <label>Adres</label>
            <input className="editable" value={company.adres || ''} onChange={e => setCompany(c => ({...c, adres: e.target.value}))} />
          </div>
          <div className="grid2" style={{marginBottom:10}}>
            <div className="field">
              <label>NIP</label>
              <input className="editable" value={company.nip || ''} onChange={e => setCompany(c => ({...c, nip: e.target.value}))} />
            </div>
            <div className="field">
              <label>Telefon</label>
              <input className="editable" value={company.telefon || ''} onChange={e => setCompany(c => ({...c, telefon: e.target.value}))} />
            </div>
          </div>
          <div className="grid2" style={{marginBottom:14}}>
            <div className="field">
              <label>Email</label>
              <input className="editable" value={company.email || ''} onChange={e => setCompany(c => ({...c, email: e.target.value}))} />
            </div>
            <div className="field">
              <label>WWW</label>
              <input className="editable" value={company.www || ''} onChange={e => setCompany(c => ({...c, www: e.target.value}))} />
            </div>
          </div>
          <button className="btn btn-primary btn-sm" onClick={handleSaveCompany} disabled={savingCompany}>
            {savingCompany ? 'Zapisywanie…' : '💾 Zapisz dane oferenta'}
          </button>
        </div>
      </div>

      <div className="card" style={{marginTop:16}}>
        <div className="card-title">Informacje o systemie</div>
        <div className="grid2">
          <div style={{fontSize:13}}>
            {[
              ['Tryb', DEMO_MODE ? '⚠ Demo (bez zapisu)' : '✓ Połączono z Google Sheets'],
              ['Backend URL', DEMO_MODE ? 'Nie skonfigurowany' : BACKEND_URL.slice(0, 40) + '…'],
              ['Wersja', '3.0'],
            ].map(([k,v]) => (
              <div key={k} style={{display:'flex',justifyContent:'space-between',padding:'8px 0',borderBottom:`1px solid ${C.gray200}`}}>
                <span style={{color:C.gray400}}>{k}</span>
                <span style={{fontWeight:500,color:C.navy}}>{v}</span>
              </div>
            ))}
          </div>
          <div style={{background:C.amberLt,borderRadius:8,padding:14}}>
            <div style={{fontSize:12,fontWeight:700,color:'#7a5200',marginBottom:8}}>
              📋 Instrukcja podłączenia Google Sheets
            </div>
            <ol style={{fontSize:12,color:'#7a5200',paddingLeft:16,lineHeight:1.8}}>
              <li>Otwórz <strong>script.google.com</strong></li>
              <li>Nowy projekt → wklej kod z pliku <code>Code.gs</code></li>
              <li>Wdróż → Nowe wdrożenie → Aplikacja webowa</li>
              <li>Wykonaj jako: <strong>Ty</strong>, Dostęp: <strong>Wszyscy</strong></li>
              <li>Skopiuj URL wdrożenia</li>
              <li>Wklej URL w pliku .jsx w zmiennej <code>BACKEND_URL</code></li>
            </ol>
          </div>
        </div>
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// CZCIONKA OUTFIT — pełne wsparcie polskich znaków diakrytycznych
// Wbudowana jako base64, żeby PDF nie zależał od żadnego zewnętrznego zasobu
// i żeby uniknąć błędu transliteracji znaków (ą, ć, ę, ł, ń, ó, ś, ź, ż)
// charakterystycznego dla domyślnej czcionki helvetica w jsPDF.
// ══════════════════════════════════════════════════════════════════════════════
const OUTFIT_REGULAR_B64 = "";
const OUTFIT_BOLD_B64 = "";

let _outfitRegistered = false;
function registerOutfitFont(doc) {
  if (!_outfitRegistered) {
    doc.addFileToVFS('Outfit-Regular.ttf', OUTFIT_REGULAR_B64);
    doc.addFont('Outfit-Regular.ttf', 'Outfit', 'normal');
    doc.addFileToVFS('Outfit-Bold.ttf', OUTFIT_BOLD_B64);
    doc.addFont('Outfit-Bold.ttf', 'Outfit', 'bold');
    _outfitRegistered = true;
  } else {
    // jsPDF rejestruje fonty per-instancję dokumentu, więc trzeba dodać je
    // do VFS każdego nowego doc, ale unikamy ponownego dekodowania base64.
    doc.addFileToVFS('Outfit-Regular.ttf', OUTFIT_REGULAR_B64);
    doc.addFont('Outfit-Regular.ttf', 'Outfit', 'normal');
    doc.addFileToVFS('Outfit-Bold.ttf', OUTFIT_BOLD_B64);
    doc.addFont('Outfit-Bold.ttf', 'Outfit', 'bold');
  }
  doc.setFont('Outfit', 'normal');
}

// ══════════════════════════════════════════════════════════════════════════════
// GENEROWANIE PDF OFERTY (jsPDF) — styl minimalistyczny / techniczny
// ══════════════════════════════════════════════════════════════════════════════
async function generateOfferPdf(offer, products, companyInfo) {
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ unit: 'mm', format: 'a4' });
  registerOutfitFont(doc);

  const pageW = 210, margin = 18;
  const RIGHT = pageW - margin;
  let y = 20;

  // Jednolita, stonowana paleta tekstu — hierarchia tworzona przez wagę i szarość,
  // nie przez różnicowanie wielkości fontu.
  const INK    = [26, 26, 26];   // tekst główny
  const GRAY   = [119, 119, 119]; // etykiety, dane pomocnicze
  const LIGHT  = [136, 136, 136]; // najmniej istotne (stopka)
  const RULE_D = [26, 26, 26];   // ciemna linia (separator główny)
  const RULE_L = [229, 229, 229]; // jasna linia (separator sekcji)
  const RULE_VL= [242, 242, 242]; // bardzo jasna linia (pod pozycją)

  const FS = 10;        // jedyny rozmiar fontu dla prawie całego dokumentu
  const FS_TOTAL = 11;  // wartość całkowita brutto — jedyny wyjątek
  const FS_NOTE = 9;    // uwagi do pozycji — odrobinę mniejsze, kursywą

  const setText = (color) => doc.setTextColor(color[0], color[1], color[2]);
  const setLine = (color) => doc.setDrawColor(color[0], color[1], color[2]);

  // ── Logo (lewo) + dane oferenta (prawo) ──────────────────────────────────────
  try {
    doc.addImage(LOGO_BASE64, 'PNG', margin, y - 6, 32, 21.3);
  } catch(e) { /* logo opcjonalne, jeśli niedostępne */ }

  doc.setFont('Outfit', 'bold'); doc.setFontSize(FS); setText(INK);
  doc.text(companyInfo?.nazwa_firmy || 'MerTech Systems', RIGHT, y - 4, { align: 'right' });
  doc.setFont('Outfit', 'normal'); doc.setFontSize(FS); setText(GRAY);
  const companyLines = [
    companyInfo?.adres || '',
    companyInfo?.nip ? `NIP: ${companyInfo.nip}` : '',
    companyInfo?.telefon || '',
    companyInfo?.email || '',
  ].filter(Boolean);
  companyLines.forEach((line, i) => {
    doc.text(line, RIGHT, y + 1 + i * 4.6, { align: 'right' });
  });

  y += 22;
  setLine(RULE_D); doc.setLineWidth(0.5);
  doc.line(margin, y, RIGHT, y);
  y += 11;

  // ── Odbiorca (lewo) / Nr oferty, Data, Ważność (prawo) ───────────────────────
  const blockTop = y;

  doc.setFont('Outfit', 'normal'); doc.setFontSize(FS); setText(GRAY);
  doc.text('ODBIORCA', margin, blockTop);
  doc.setFont('Outfit', 'bold'); setText(INK);
  doc.text(String(offer['Klient'] || ''), margin, blockTop + 5.5);
  doc.setFont('Outfit', 'normal'); setText(GRAY);
  const clientLines = [
    offer['Adres klienta'] || '',
    offer['NIP klienta'] ? `NIP: ${offer['NIP klienta']}` : '',
  ].filter(Boolean);
  clientLines.forEach((l, i) => doc.text(String(l), margin, blockTop + 10.5 + i * 4.6, { maxWidth: 95 }));

  // Prawa kolumna: Nr oferty / Data wystawienia / Okres ważności
  const rightColX = RIGHT;
  const rowsRight = [
    ['Nr oferty: ', String(offer['Nr oferty'] || '')],
    ['Data wystawienia: ', String(offer['Data'] || '')],
    ['Okres ważności: ', `${offer['Ważność (dni)'] || ''} dni od daty wystawienia`],
  ];
  rowsRight.forEach(([label, value], i) => {
    const yy = blockTop + i * 5.2;
    doc.setFont('Outfit', 'normal'); setText(GRAY);
    const labelW = doc.getTextWidth(label);
    doc.setFont('Outfit', 'bold'); setText(INK);
    const valueW = doc.getTextWidth(value);
    doc.text(value, rightColX, yy, { align: 'right' });
    doc.setFont('Outfit', 'normal'); setText(GRAY);
    doc.text(label, rightColX - valueW, yy, { align: 'right' });
  });

  y = blockTop + Math.max(10.5 + clientLines.length * 4.6, rowsRight.length * 5.2) + 8;

  // ── Przedmiot oferty ──────────────────────────────────────────────────────────
  if (offer['Przedmiot oferty']) {
    doc.setFont('Outfit', 'normal'); doc.setFontSize(FS); setText(GRAY);
    doc.text('PRZEDMIOT OFERTY', margin, y);
    y += 5.2;
    doc.setFont('Outfit', 'normal'); setText(INK);
    const subjLines = doc.splitTextToSize(String(offer['Przedmiot oferty']), pageW - 2 * margin);
    doc.text(subjLines, margin, y);
    y += subjLines.length * 4.8 + 6;
  }

  // ── Przygotuj pozycje z podziałem na zakres i uwagami per-produkt ────────────
  let scope = {};
  try { scope = JSON.parse(offer['Zakres produktów JSON'] || '{}'); } catch(e) {}
  let productNotes = {};
  try { productNotes = JSON.parse(offer['Uwagi produktów JSON'] || offer['uwagi_produktow_json'] || '{}'); } catch(e) {}

  const allLineItems = [
    ['1', 'Chmura punktów', offer['Chmura punktów']],
    ['2', 'Ortofotomapa', offer['Ortofotomapa']],
    ['3', 'Model 3D', offer['Model 3D']],
    ['4', 'Raport', offer['Raport']],
    ['5', 'Inspekcja wizualna', offer['Inspekcja wizualna']],
    ['6', 'Przekroje i pomiary', offer['Przekroje i pomiary']],
    ['7', 'Obliczenia mas', offer['Obliczenia mas']],
  ];

  const vatRate = 0.23;

  // ── Funkcja rysująca jedną sekcję zakresu (podstawowy / dodatkowy) ───────────
  function drawScopeSection(title, items) {
    if (items.length === 0) return;
    if (y > 250) { doc.addPage(); y = 20; }

    setLine(RULE_L); doc.setLineWidth(0.4);
    doc.line(margin, y, RIGHT, y);
    y += 6;

    doc.setFont('Outfit', 'normal'); doc.setFontSize(FS); setText(GRAY);
    doc.text(title, margin, y);
    doc.text('NETTO', RIGHT, y, { align: 'right' });
    y += 6;

    let sectionNet = 0;
    items.forEach(([id, name, val]) => {
      if (y > 270) { doc.addPage(); y = 20; }

      doc.setFont('Outfit', 'normal'); doc.setFontSize(FS); setText(INK);
      doc.text(name, margin, y);
      doc.text(pln(val), RIGHT, y, { align: 'right' });
      sectionNet += +val;
      y += 5;

      const note = (productNotes[id] || '').trim();
      if (note) {
        doc.setFont('Outfit', 'normal'); doc.setFontSize(FS_NOTE); setText(LIGHT);
        const noteLines = doc.splitTextToSize(note, pageW - 2 * margin - 4);
        doc.text(noteLines, margin + 2, y);
        y += noteLines.length * 4 + 1;
      }

      setLine(RULE_VL); doc.setLineWidth(0.3);
      doc.line(margin, y, RIGHT, y);
      y += 5;
    });

    y += 2;
    const sectionVat = sectionNet * vatRate;
    const sectionGross = sectionNet + sectionVat;

    const summaryColW = 60;
    const summaryX = RIGHT - summaryColW;

    doc.setFont('Outfit', 'normal'); doc.setFontSize(FS);
    setText(GRAY);
    doc.text('Netto', summaryX, y);
    setText(INK);
    doc.text(pln(sectionNet), RIGHT, y, { align: 'right' });
    y += 5.5;

    setText(GRAY);
    doc.text('VAT (23%)', summaryX, y);
    setText(INK);
    doc.text(pln(sectionVat), RIGHT, y, { align: 'right' });
    y += 5.5;

    setText(INK);
    doc.text('Brutto', summaryX, y);
    doc.text(pln(sectionGross), RIGHT, y, { align: 'right' });
    y += 10;
  }

  const baseItems = allLineItems.filter(([id,,val]) => +val > 0 && scope[id] === 'podstawowy');
  const extraItems = allLineItems.filter(([id,,val]) => +val > 0 && scope[id] === 'dodatkowy');
  const unscopedItems = allLineItems.filter(([id,,val]) => +val > 0 && !scope[id]);
  const baseItemsFinal = unscopedItems.length > 0 && baseItems.length === 0 && extraItems.length === 0
    ? unscopedItems : baseItems;

  drawScopeSection('ZAKRES PODSTAWOWY', baseItemsFinal);
  drawScopeSection('ZAKRES DODATKOWY', extraItems);

  // ── Wartość całkowita brutto ──────────────────────────────────────────────────
  if (y > 260) { doc.addPage(); y = 20; }
  setLine(RULE_D); doc.setLineWidth(0.5);
  doc.line(margin, y, RIGHT, y);
  y += 7;

  doc.setFont('Outfit', 'normal'); doc.setFontSize(FS_TOTAL); setText(GRAY);
  doc.text('WARTOŚĆ CAŁKOWITA BRUTTO', margin, y);
  doc.setFont('Outfit', 'bold'); setText(INK);
  doc.text(pln(offer['Wartość brutto']), RIGHT, y, { align: 'right' });
  y += 12;

  // ── Uwagi ogólne do oferty ────────────────────────────────────────────────────
  if (offer['Uwagi']) {
    if (y > 265) { doc.addPage(); y = 20; }
    doc.setFont('Outfit', 'normal'); doc.setFontSize(FS); setText(GRAY);
    doc.text('UWAGI', margin, y);
    y += 5.2;
    setText(INK);
    const uwagiLines = doc.splitTextToSize(String(offer['Uwagi']), pageW - 2 * margin);
    doc.text(uwagiLines, margin, y);
    y += uwagiLines.length * 4.8 + 6;
  }

  // ── Stopka ────────────────────────────────────────────────────────────────────
  const footerY = 285;
  setLine(RULE_L); doc.setLineWidth(0.3);
  doc.line(margin, footerY - 6, RIGHT, footerY - 6);
  doc.setFont('Outfit', 'normal'); doc.setFontSize(FS_NOTE); setText(LIGHT);
  doc.text(
    `Oferta wygenerowana elektronicznie · ${companyInfo?.nazwa_firmy || 'Mertech Systems'}`,
    pageW / 2, footerY, { align: 'center' }
  );

  doc.save(`Oferta_${(offer['Nr oferty'] || 'bez-numeru').replace(/[^a-zA-Z0-9-]/g, '_')}.pdf`);
}

window.App = App;
